import json
import re

# Load the UC patents data
uc_file = locals()['var_functions.query_db:42']
with open(uc_file, 'r') as f:
    uc_data = json.load(f)

# Step 1: Extract UC publication numbers and their CPCs
uc_pub_map = {}  # publication_number -> primary CPC codes
for record in uc_data:
    patents_info = record.get('Patents_info', '')
    cpc_data = record.get('cpc', '')

    # Extract publication number
    pub_match = re.search(r'([A-Z]{2}-\d+-[A-Z]\d+)', patents_info)
    if pub_match:
        pub_num = pub_match.group(1)

        # Parse CPC to get primary codes (inventive=true or first=true)
        primary_cpcs = []
        if cpc_data:
            try:
                cpc_list = json.loads(cpc_data)
                for cpc_item in cpc_list:
                    if cpc_item.get('inventive') or cpc_item.get('first'):
                        code = cpc_item.get('code')
                        if code:
                            primary_cpcs.append(code)
            except:
                pass

        uc_pub_map[pub_num] = list(set(primary_cpcs))

result = {
    'uc_patents_found': len(uc_data),
    'uc_publication_numbers': len(uc_pub_map),
    'sample_mapping': {k: uc_pub_map[k] for k in list(uc_pub_map.keys())[:3]}
}

print('__RESULT__:')
print(json.dumps(result))

