import json
import re

# Load UC publication numbers from previous analysis
uc_data = locals()['var_functions.query_db:46']
uc_pub_numbers = set(uc_data['uc_publication_numbers'])

# Load sample patent data to find citations
data_file = locals()['var_functions.query_db:48']
with open(data_file, 'r') as f:
    patents_data = json.load(f)

# Find patents that cite UC patents and get their assignees
citing_patents = []  # List of (citing_patent_info, cited_uc_patent, citing_assignee)
uc_citation_map = {}  # cited_uc_patent -> list of citing patents with assignees

for record in patents_data:
    patents_info = record.get('Patents_info', '')
    citation_data = record.get('citation', '')

    if citation_data:
        try:
            citations = json.loads(citation_data)
            # Check if any citation is a UC patent
            for citation in citations:
                pub_num = citation.get('publication_number', '')
                if pub_num in uc_pub_numbers:
                    # This patent cites a UC patent
                    # Extract assignee from Patents_info
                    assignee_match = re.search(r'^([A-Z][^,]+) holds|^([A-Z][^,]+) is|^Application [^,]+ from [^,]+, (owned by|assigned to|belonging to) ([A-Z][^,\.]+)', patents_info)

                    if assignee_match:
                        # Get the first non-None group
                        assignee = next((g for g in assignee_match.groups() if g), '')
                        if assignee:
                            # Clean up the assignee name
                            assignee = assignee.strip()
                            # Skip if it's UNIV CALIFORNIA
                            if 'UNIV CALIFORNIA' not in assignee.upper() and 'UNIVERSITY OF CALIFORNIA' not in assignee.upper():
                                citing_patents.append({
                                    'citing_patent': patents_info,
                                    'cited_uc_patent': pub_num,
                                    'citing_assignee': assignee
                                })

                                if pub_num not in uc_citation_map:
                                    uc_citation_map[pub_num] = []
                                uc_citation_map[pub_num].append(assignee)
        except:
            pass

# Get unique assignees and their citation counts
assignee_citations = {}
for item in citing_patents:
    assignee = item['citing_assignee']
    if assignee not in assignee_citations:
        assignee_citations[assignee] = set()
    assignee_citations[assignee].add(item['cited_uc_patent'])

result = {
    'total_citing_patents': len(citing_patents),
    'unique_citing_assignees': len(assignee_citations),
    'sample_citations': citing_patents[:5],
    'uc_citation_map_sample': {k: uc_citation_map[k] for k in list(uc_citation_map.keys())[:3]},
    'assignee_citation_summary': {k: len(v) for k, v in list(assignee_citations.items())[:10]}
}

print('__RESULT__:')
print(json.dumps(result))

